              variant="outline"
              className={`rounded-full h-11 w-11 p-0 ${!mockCameraReady ? 'bg-gray-200 text-gray-500' : ''}`}
              title={mockCameraReady ? 'Turn off camera' : 'Turn on camera'}
            >
              {mockCameraReady ? <Video className="h-4 w-4" /> : <VideoOff className="h-4 w-4" />}
