            </div>
            <Badge className={`mt-2 ${
              mockFeedback.interview_readiness === 'ready' ? 'bg-green-100 text-green-700' :
              mockFeedback.interview_readiness === 'almost_ready' ? 'bg-amber-100 text-amber-700' :
              'bg-red-100 text-red-700'
